  SUBSCRIPTIONS[name] = {
    "description": description, 
    "price": price
  }

def show_subscriptions():
  for name, subscription in SUBSCRIPTIONS.items():
    print(name, subscription["description"], subscription["price"])

def unregister_subscription(name):
  try:
    del SUBSCRIPTIONS[name]
  except KeyError:
    print("Subscription not found")

def get_subscription_by_name(name):
  return SUBSCRIPTIONS[name]

if __name__ == "__main__":
  register_subscription("Video Streaming", "Stream videos to your devices", 10)
  register_subscription("Gaming", "Access latest games", 30)

  show_subscriptions()
```

